import { AgentRuntime } from '@google/adk';

async function run() {
  const runtime = new AgentRuntime({ configPath: 'agent.yaml' });
  const result = await runtime.execute({ prompt: 'Hello agent!' });
  console.log('Response:', result.content);
}
run();

runtime = AgentRuntime(config_path="agent.yaml")
step_generator = runtime.execute_iterative(prompt="Calculate sales tax for $1500")

for step in step_generator:
    print(f"Step Type: {step.type}")
    if step.type == "tool_call":
        print(f"Invoking Tool: {step.tool_name} with {step.args}")
    elif step.type == "model_thinking":
        print("Agent is processing...")

const runtime = new AgentRuntime({ configPath: 'agent.yaml' });

runtime.on('tool:start', (event) => {
  console.log(`[AUDIT] Tool execution requested: ${event.toolName}`);
});

runtime.on('model:request', (event) => {
  console.log(`[METRIC] Tokens sent: ${event.promptTokens}`);
});
